sys_ui_page.client_script:
initPage();

// Use this function to remove the disabled attribute from the submit button
function enableSubmitButton() {
	gel('submit').disabled = gel('newCancellationReason').value.length == 0;
}

// Use this function to initialize variables at page load
function initPage() {
	gel('newCancellationReason').value = gel('newCancellationReason').value.trim();
	var reasonLength = gel('newCancellationReason').value.length;

	if (reasonLength == 0) {
		gel('submit').disabled = true;
	} else {
		gel('submit').disabled = false;
	}
}

// dialog_button id="cancel" was clicked, user does not want to delete the task
function onCancel() {
    // below will auto close popup
    GlideDialogWindow.get().destroy();
    return false;
}

// dialog_button id="submit" was clicked, user confirms wanting to delete the task
function onSubmit() {
    return true;
}

sys_ui_page.processing_script:
cancel();

function cancel() {
    var grTasksCancel = new GlideRecord("x_153465_discovert_route_task_instance");
    grTasksCancel.addQuery('sys_id', sysid);
    grTasksCancel.query();

    if (grTasksCancel.next()) {
		var gdt2 = new GlideDateTime();
		// newCancellationReason is the name attribute on HTML textarea tag
        new Task_uiAction().uiAction_CancelTasks(grTasksCancel, newCancellationReason, gdt2);
    }

    response.sendRedirect("/x_153465_discovert_route_task_instance.do?sys_id=" + sysid);
}
